Hello, I have extended flask-ask to work with the echo show for a project at work. I thought I would share my code but I have no idea how to branch and make a pull request.

I have changed the inbuilt display_element_selected to follow the intent scheme as
`python
@ask.display("DisplayTemplateToken")
def foo(item_display_token):
    # Handle event
`

from core.py
`python
def display(self, display_template_token, mapping={}, convert={}, default={}):
        """Decorator routes Alexa Display.ElementSelected request to the wrapped view function.
            **template must have a token as well as selected items**

        @ask.display('display_template_token')
        def eval_element(selected_token):
            return "", 200

        The wrapped function is registered as the display view function
        and renders the response for requests.

        Arguments:
            display_template_token {str} -- display template token located at decorators[-]['template']['token']
        """

        def decorator(f):
            self._intent_view_funcs[display_template_token] = f

            self._intent_mappings[display_template_token] = mapping
            self._intent_converts[display_template_token] = convert
            self._intent_defaults[display_template_token] = default

            @wraps(f)
            def wrapper(*args, **kw):
                self._flask_view_func(*args, **kw)
            return f
        return decorator

    def _flask_view_func(self, *args, **kwargs):
        ask_payload = self._alexa_request(verify=self.ask_verify_requests)
        dbgdump(ask_payload)
        request_body = models._Field(ask_payload)

        self.request = request_body.request
        self.version = request_body.version
        self.context = getattr(request_body, 'context', models._Field())
        self.session = getattr(request_body, 'session', self.session) # to keep old session.attributes through AudioRequests

        if not self.session:
            self.session = models._Field()
        if not self.session.attributes:
            self.session.attributes = models._Field()

        self._update_stream()

        # add current dialog state in session
        try:
            self.session["dialogState"] = request.dialogState
        except KeyError:
            self.session["dialogState"] = "unknown"

        try:
            if self.session.new and self._on_session_started_callback is not None:
                self._on_session_started_callback()
        except AttributeError:
            pass

        result = None
        request_type = self.request.type

        if request_type == 'LaunchRequest' and self._launch_view_func:
            result = self._launch_view_func()
        elif request_type == 'SessionEndedRequest':
            if self._session_ended_view_func:
                result = self._session_ended_view_func()
            else:
                result = "{}", 200
        elif request_type == 'IntentRequest' and self._intent_view_funcs:
            result = self._map_intent_to_view_func(self.request.intent)()
        elif 'AudioPlayer' in request_type:
            result = self._map_player_request_to_func(self.request.type)()
            # routes to on_playback funcs
            # user can also access state of content.AudioPlayer with current_stream
        elif request_type == 'Display.ElementSelected' and self._intent_view_funcs:
            result = self._map_display_to_view_func(self.context.Display, self.request.token)()

        if result is not None:
            if isinstance(result, models._Response):
                return result.render_response()
            return result
        return "", 400

    def _map_display_to_view_func(self, display, item_token):
        """Provides appropriate parameters to the display function."""
        if display.token in self._intent_view_funcs:
            view_func = self._intent_view_funcs[display.token]
        else:
            raise NotImplementedError('Display "{}" not found'.format(display.token))

        argspec = inspect.getargspec(view_func)
        arg_names = argspec.args
        arg_value = self._map_params_to_view_args(display.token, arg_names)
        return partial(view_func, *arg_value)
`

from model.py
`python
